/**
  **************************************************************************
  * @file     init.h
  * @brief    系统初始化头文件
  *           包含所有初始化函数的声明及必要的全局变量外部引用。
  **************************************************************************
  */
#ifndef __INIT_H
#define __INIT_H

/* 包含必要的库头文件 */
#include "at32f403a_407_board.h"
#include "at32f403a_407_clock.h"
#include "usbd_core.h"
#include "cdc_class.h"
#include "cdc_desc.h"
#include "usbd_int.h"
#include "i2c_application.h"
#include <string.h>
#include "LOG.h"
#include "SPI_LCD.h"
#include "24cxx1.h"
#include "24cxx.h"
#include "LCD.h"
#include "EEPROM_MANGER.h"
#include "flash_store.h"


#define FACTORY_VERSION  1

/* I2C 配置宏定义 */
#define I2C_TIMEOUT        300
#define I2C2_SPEED         400000
#define I2C2_ADDRESS       0xa0
#define I2C2_PORT          I2C2
#define I2C2_CLK           CRM_I2C2_PERIPH_CLOCK
#define I2C2_SCL_PIN       GPIO_PINS_10
#define I2C2_SCL_GPIO_PORT GPIOB
#define I2C2_SCL_GPIO_CLK  CRM_GPIOB_PERIPH_CLOCK
#define I2C2_SDA_PIN       GPIO_PINS_11
#define I2C2_SDA_GPIO_PORT GPIOB
#define I2C2_SDA_GPIO_CLK  CRM_GPIOB_PERIPH_CLOCK
#define I2C1_SPEED         400000
#define I2C1_ADDRESS       0xa0
#define I2C1_PORT          I2C1
#define I2C1_CLK           CRM_I2C1_PERIPH_CLOCK
#define I2C1_SCL_PIN       GPIO_PINS_6
#define I2C1_SCL_GPIO_PORT GPIOB
#define I2C1_SCL_GPIO_CLK  CRM_GPIOB_PERIPH_CLOCK
#define I2C1_SDA_PIN       GPIO_PINS_7
#define I2C1_SDA_GPIO_PORT GPIOB
#define I2C1_SDA_GPIO_CLK  CRM_GPIOB_PERIPH_CLOCK

/* 缓存与地址宏定义 */
#define BUF_SIZE           8
#define SN_SIZE            15
#define E32K_SIZE          8224 //8192+32
#define SN_ADDR            0x1FE0
#define CONN_ADDR          0x7fff
#define MODEL_ADDR         0x7FFA
#define MODEL_BACK_ADDR    0x1FDD
#define MODEL_BACK_LEN         3
#define MODEL_LEN  5
#define TYPE_ADDR         0x1FF0
#define TYPE_SIZE         15

#define EepromPageDelay    delay_ms(5)
#define D3s                30
#define SN_LEN             SN_SIZE
#define BUFFER_MONITOR_INTERVAL 1000

/* 错误统计结构体 */
typedef struct {
    uint32_t total_i2c_operations;
    uint32_t i2c_timeout_errors;
    uint32_t crc_errors;
    uint32_t verification_errors;
    uint32_t sn_changed_errors;
    uint32_t eeprom_write_failures;
} error_stats_t;



/* 全局变量外部声明 (在 init.c 中定义) */
extern error_stats_t error_stats;
extern usbd_core_type usb_core_dev;
extern i2c_handle_type hi2c1, hi2c2;
extern spi_init_type spi_init_struct;
extern crm_clocks_freq_type crm_clocks_freq_struct;

extern uint8_t ConnI2c1_flag, ConnI2c2_flag;
extern uint8_t CheckEeFlag;
extern uint16_t Page_Count;
extern uint32_t Regaddr, RegLen;
extern uint8_t tx_buf1[BUF_SIZE];
extern uint8_t testbuf[8];

extern uint8_t response_data[E32K_SIZE];
extern uint8_t rxdata[E32K_SIZE];
extern uint8_t crc[2];
extern uint8_t Count1, Count2;
extern uint16_t framecout;
extern uint8_t FrameFlag;
extern uint8_t FrameOldStatus, FrameNewStatus;
extern uint8_t FrameFinish;
extern uint8_t I2c1_SN[SN_SIZE], I2c2_SN[SN_SIZE], I2c1_MODEL[TYPE_SIZE], I2c2_MODEL[TYPE_SIZE];
extern uint8_t connectstatus[9];
extern uint8_t MworeWr[5];
extern uint8_t ResetLR[5];
extern _EEPROM_STATUS_ EEPROM_Status;
extern uint64_t timecunt, PflagCout1, PflagCout2;
extern uint8_t PowerFlag1, PowerFlag2;
extern uint8_t WATCHDOGFLAG;
extern uint8_t WATCHDAT[6];
extern uint64_t WATCHCOUNT;
extern uint8_t download_mode_flag;
extern uint8_t download_mode_delay;
extern uint8_t consecutive_fail_count[2];

/* 初始化函数声明 */
void System_Clock_Init(void);
void GPIO_Init(void);
void SPI_Init(void);
void I2C_GPIO_Init(void);
void I2C_Peripheral_Init(i2c_handle_type *hi2c);
void USB_Init(void);
void Timer_Init(void);
void Watchdog_Init(void);
void System_Init(void);

/* 工具函数声明 */
void GetCrC(uint8_t *pSource, uint32_t len, uint8_t *crc);
uint8_t i2c_write_with_retry(i2c_handle_type *hi2c, uint16_t addr, uint8_t *data, uint16_t len, uint8_t retry_count);
uint8_t i2c_read_with_retry(i2c_handle_type *hi2c, uint16_t addr, uint8_t *data, uint16_t len, uint8_t retry_count);
void I2c1ConfigGpioIn(void);
void I2c2ConfigGpioIn(void);
void usb_clock48m_select(usb_clk48_s clk_s);
void i2c_lowlevel_init(i2c_handle_type *hi2c);

/* 电源控制函数 */


void I2C1_Power_On(void);
void I2C1_Power_Off(void);
void I2C2_Power_On(void);
void I2C2_Power_Off(void);
uint8_t read_I2C2_power_pin_status(void);
uint8_t read_I2C1_power_pin_status(void);

// LCD相关函数声明
void GPIO_OLED_InitConfig(void);
void LCD_DISPLAY(void);


// SEGGER RTT
void SEGGER_RTT_Init(void);
#endif /* __INIT_H */

