2	 **************************************************************************
3	 * @file     main.c
4	 * @version  v1.0.0
5	 * @date     2026-03-03
6	 * @brief    主程序 - 助听器编程器 (FreeRTOS版本)
7	 **************************************************************************
8	 */
9	#include "init.h"
10	#include "usb_task.h"
11	#include "i2c_task.h"
12	#include "FreeRTOS.h"
13	#include "task.h"
14	#include "queue.h"
15	#include "semphr.h"
16	
17	/* 全局变量声明 (在init.c中定义) */
18	extern uint8_t ConnI2c1_flag, ConnI2c2_flag;
19	extern uint8_t I2c1_SN[], I2c2_SN[];
20	extern uint8_t I2c1_MODEL[], I2c2_MODEL[];
21	extern uint64_t timecunt;
22	extern uint16_t framecout;
23	extern uint8_t FrameFlag, FrameFinish;
24	
25	extern i2c_handle_type hi2c1, hi2c2;
26	extern usbd_core_type usb_core_dev;
27	
28	/* FreeRTOS对象 */
29	QueueHandle_t xCommandQueue  = NULL;
30	QueueHandle_t xResponseQueue = NULL;
31	SemaphoreHandle_t xUSBMutex  = NULL;
32	SemaphoreHandle_t xI2CMutex  = NULL;
33	
34	/* 任务句柄 */
35	static TaskHandle_t xUSBTaskHandle  = NULL;
36	static TaskHandle_t xI2CTaskHandle  = NULL;
37	static TaskHandle_t xCtrlTaskHandle = NULL;
38	
39	// 全局记录表，最多保存5个设备记录
40	static device_record_t device_records[FLASH_MAX_RECORDS] = {0};
41	static uint8_t record_count                              = 0;
42	static uint8_t record_current                            = 0;
43	/* 局部函数声明 */
44	static void Ctrl_Task(void *pvParameters);
45	void monitor_buffer_usage(void);
46	void Get_eeprom_SN(void);
47	
48	/* 设备配置结构体 */
49	typedef struct {
50	    uint8_t ear_index;                    /* 0=左耳, 1=右耳 */
51	    const char *ear_name;                 /* "Left" / "Right" */
52	    i2c_handle_type *hi2c;                 /* I2C handle */
53	    uint8_t *conn_flag;                   /* 连接标志 */
54	    uint8_t *sn_buf;                      /* SN缓存 */
55	    uint8_t *model_buf;                    /* 物料号缓存 */
56	    uint8_t *last_sn;                      /* 上一次SN缓存 */
57	    uint8_t *skip_counter;                /* 跳过计数器 */
58	    uint8_t need_read;                     /* 需要读取标志 */
59	} ear_config_t;
60	
61	/* 通用设备处理函数 */
62	static uint8_t process_ear_device(const ear_config_t *cfg,
63	                                   uint8_t *current_sn,
64	                                   uint8_t *current_model,
65	                                   uint8_t *skip_counter,
66	                                   uint8_t need_read);
67	
68	#if FACTORY_VERSION
69	static uint8_t process_ear_device_factory(const ear_config_t *cfg,
70	                                            uint8_t *current_sn,
71	                                            uint8_t *current_model,
72	                                            uint8_t *skip_counter);
73	#endif
74	
75	/**
76	 * @brief 验证SN的前两个字节是否为字母 (A-Z, a-z)
77	 * @param sn 指向SN字节数组的指针
78	 * @return 1-有效（是字母），0-无效
79	 */
80	uint8_t is_sn_valid(uint8_t *sn)
81	{
82	    // 检查前两个字节是否为字母 (ASCII: A-Z 65-90, a-z 97-122)
83	    if ((sn[0] >= 'A' && sn[0] <= 'Z') || (sn[0] >= 'a' && sn[0] <= 'z')) {
84	        if ((sn[1] >= 'A' && sn[1] <= 'Z') || (sn[1] >= 'a' && sn[1] <= 'z')) {
85	            LOGI("SN first two letters: 0x%02X('%c'), 0x%02X('%c')", sn[0], sn[0], sn[1], sn[1]);
86	            return 1; // 有效
87	        }
88	    }
89	    LOGW("SN first two letters is err: 0x%02X, 0x%02X", sn[0], sn[1]);
90	    return 0; // 无效
91	}
92	
93	/**
94	 * @brief 根据SN在记录表中查找记录
95	 * @param sn 要查找的序列号
96	 * @return 记录索引，-1表示未找到
97	 */
98	int find_record_by_sn(uint8_t *sn)
99	{
100	    for (int i = 0; i < FLASH_MAX_RECORDS; i++) {
101	        if (memcmp(device_records[i].sn, sn, SN_SIZE) == 0) {
102	            return i; // 找到匹配的记录
103	        }
104	    }
105	    return -1; // 未找到
106	}
107	
108	/**
109	 * @brief 增强的物料号验证函数
110	 * @param model 当前读取的物料号
111	 * @param sn 设备的SN（可选，用于查找存储记录）
112	 * @return 1-有效，0-无效
113	 */
114	uint8_t is_model_valid(uint8_t *model, uint8_t *sn)
115	{
116	    // 1. 先进行基本检查
117	    uint8_t all_ff         = 1;
118	    uint8_t all_00         = 1;
119	    uint8_t has_valid_data = 0;
120	
121	    for (int i = 0; i < MODEL_LEN; i++) {
122	        if (model[i] != 0xFF) all_ff = 0;
123	        if (model[i] != 0x00) all_00 = 0;
124	        if (model[i] != 0xFF && model[i] != 0x00) has_valid_data = 1;
125	    }
126	
127	    if (all_ff || all_00) {
128	        LOGW("Model is all 0xFF or all 0x00");
129	        return 0;
130	    }
131	
132	    if (model[0] != 0x11) {
133	        LOGW("MODLE [0] is err======");
134	        return 0;
135	    }
136	
137	    if (model[2] == 0 && model[3] == 0) {
138	        LOGE("is_model_valid is all 0x00=============");
139	        return 0;
140	    }
141	
142	    // 2. 如果提供了SN，查找存储的记录
143	    if (sn != NULL) {
144	        int record_idx = find_record_by_sn(sn);
145	        if (record_idx >= 0) {
146	            // 比较物料号
147	            uint8_t models_match = 1;
148	            for (int i = 0; i < MODEL_LEN; i++) {
149	                if (model[i] != device_records[record_idx].model[i]) {
150	                    models_match = 0;
151	                    break;
152	                }
153	            }
154	
155	            if (models_match) {
156	                LOGI("Model matches stored record");
157	                uint8_t current_sn[SN_LEN] = {0};
158	                memcpy(current_sn, sn, SN_LEN);
159	                LOGW("sn: %02X%02X%02X%02X%02X%02X%02X%02X",
160	                     current_sn[0], current_sn[1], current_sn[2], current_sn[3],
161	                     current_sn[4], current_sn[5], current_sn[6], current_sn[7]);
162	                return 1;
163	            } else {
164	                LOGW("Model does NOT match stored record");
165	                return 0;
166	            }
167	        }
168	    }
169	    // LOGI("No matching SN record found, but model has valid data");
170	    // 3. 没有SN或没有记录，使用原来的逻辑
171	    return has_valid_data;
172	}
