174	/**
175	 * @brief 添加或更新记录
176	 * @param sn 序列号
177	 * @param model 物料号
178	 * @return 记录索引，-1表示未保存（SN无效或未找到），-2表示SN格式无效
179	 */
180	int add_or_update_record(uint8_t *sn, uint8_t *model)
181	{
182	    // 1. 新增：检查SN前两位是否为字母
183	    if (!is_sn_valid(sn)) {
184	        // LOGW("SN first two letters is err");
185	        return -2; // 返回-2表示因SN无效而未保存
186	    }
187	
188	    int idx = find_record_by_sn(sn);
189	
190	    if (idx >= 0) {
191	        // 更新现有记录
192	        if (model != NULL) {
193	            memcpy(device_records[idx].model, model, MODEL_LEN);
194	            device_records[idx].model_valid = 1;
195	            LOGI("===============UPDATE RECORD====================");
196	        }
197	        return idx;
198	    } else {
199	        // 添加新记录
200	        if (record_count < FLASH_MAX_RECORDS || record_current < FLASH_MAX_RECORDS) {
201	            idx = record_current;
202	            record_count++;
203	            record_current++;
204	            if (record_count >= FLASH_MAX_RECORDS) record_count = FLASH_MAX_RECORDS;
205	            if (record_current >= FLASH_MAX_RECORDS) record_current = 0;
206	        }
207	
208	        memcpy(device_records[idx].sn, sn, SN_LEN);
209	        device_records[idx].sn_valid = 1;
210	
211	        if (model != NULL) {
212	            memcpy(device_records[idx].model, model, MODEL_LEN);
213	            device_records[idx].model_valid = 1;
214	        } else {
215	            device_records[idx].model_valid = 0;
216	        }
217	
218	        return idx;
219	    }
220	}
