653	    }
654	}
655	
656	/**
657	 * @brief 非工厂版本 - 处理单个耳朵设备(左/右耳通用)
658	 * @return 1=成功, 0=失败
659	 */
660	static uint8_t process_ear_device(const ear_config_t *cfg,
661	                                   uint8_t *current_sn,
662	                                   uint8_t *current_model,
663	                                   uint8_t *skip_counter,
664	                                   uint8_t need_read)
665	{
666	    uint8_t read_success = 0;
667	    uint8_t i;
668	
669	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
670	        *skip_counter = 4;
671	        LOGW("%s ear: failed to take I2C mutex", cfg->ear_name);
672	        return 0;
673	    }
674	
675	    // 1. 读取SN
676	    read_success = i2c_read_with_retry(cfg->hi2c, SN_ADDR, current_sn, SN_LEN, 3);
677	
678	    if (read_success) {
679	        // 2. 读取物料号
680	        read_success = i2c_read_with_retry(cfg->hi2c, MODEL_ADDR, current_model, MODEL_LEN, 2);
681	
682	        if (read_success) {
683	            // 3. 检查物料号是否有效
684	            uint8_t model_valid = is_model_valid(current_model, current_sn);
685	
686	            if (!model_valid) {
687	                LOGW("%s ear model number is invalid!", cfg->ear_name);
688	
689	                // 4. 在记录表中查找此SN
690	                int record_idx = find_record_by_sn(current_sn);
691	                if (record_idx < 0) {
692	                    LOGI("Record not in memory, reloading from Flash...");
693	                    uint8_t loaded = flash_store_load_all(device_records, FLASH_MAX_RECORDS);
694	                    if (loaded > 0) {
695	                        record_count = loaded;
696	                        record_current = (loaded < FLASH_MAX_RECORDS) ? loaded : 0;
697	                        LOGI("Reloaded %d records from Flash, record_current=%d", loaded, record_current);
698	                        record_idx = find_record_by_sn(current_sn);
699	                    }
700	                }
701	
702	                if (record_idx >= 0 && device_records[record_idx].model_valid) {
703	                    // 找到有效记录，恢复物料号
704	                    LOGI("Found valid model in record, attempting recovery...");
705	                    LOG("sn: %02X%02X%02X%02X%02X%02X%02X%02X",
706	                        current_sn[0], current_sn[1], current_sn[2], current_sn[3],
707	                        current_sn[4], current_sn[5], current_sn[6], current_sn[7]);
708	                    LOG("recorded model: %02X%02X%02X%02X%02X",
709	                        device_records[record_idx].model[0], device_records[record_idx].model[1],
710	                        device_records[record_idx].model[2], device_records[record_idx].model[3],
711	                        device_records[record_idx].model[4]);
712	
713	                    uint8_t write_success = i2c_write_with_retry(cfg->hi2c, MODEL_ADDR,
714	                                                                 device_records[record_idx].model,
715	                                                                 MODEL_LEN, 3);
716	                    if (write_success) {
717	                        LOGI("%s ear model number recovered successfully", cfg->ear_name);
718	                    } else {
719	                        LOGE("Failed to write model number!");
720	                    }
721	                } else {
722	                    // 没有记录，从备份恢复
723	                    LOGE("%d=================No valid model record found for this SN", record_idx);
724	                    uint8_t current_backup_model[MODEL_BACK_LEN] = {0};
725	
726	                    read_success = i2c_read_with_retry(cfg->hi2c, MODEL_BACK_ADDR, current_backup_model, MODEL_BACK_LEN, 3);
727	                    if (read_success) {
728	                        LOGI("Read backup model number successfully");
729	                        LOG("backup model: %02X%02X%02X",
730	                            current_backup_model[0], current_backup_model[1], current_backup_model[2]);
731	
732	                        uint8_t new_model[MODEL_LEN] = {0};
733	                        new_model[0] = 0x11;
734	                        new_model[1] = current_backup_model[0];
735	                        new_model[2] = current_backup_model[1];
736	                        new_model[3] = current_backup_model[2];
737	                        new_model[4] = 0x02;
738	
739	                        LOG("New model to write: %02X%02X%02X%02X%02X",
740	                            new_model[0], new_model[1], new_model[2], new_model[3], new_model[4]);
741	
742	                        if (new_model[2] == 0 && new_model[3] == 0) {
743	                            LOGE("Read New model is all 0x00 ERR");
744	                        } else {
745	                            uint8_t write_success = i2c_write_with_retry(cfg->hi2c, MODEL_ADDR,
746	                                                                         new_model, MODEL_LEN, 3);
747	                            if (write_success) {
748	                                LOGI("%s ear model number recovered from backup successfully", cfg->ear_name);
749	                                int idx = find_record_by_sn(current_sn);
750	                                if (idx < 0) {
751	                                    idx = add_or_update_record(current_sn, new_model);
752	                                    if (idx >= 0) {
753	                                        if (flash_store_save_record(&device_records[idx])) {
754	                                            LOGI("Record saved to Flash");
755	                                        } else {
756	                                            LOGE("Failed to save record to Flash!");
757	                                        }
758	                                    }
759	                                }
760	                            } else {
761	                                LOGE("Failed to write backup model number!");
762	                            }
763	                        }
764	                    } else {
765	                        LOGE("Failed to read backup model number!");
766	                    }
767	                }
768	            } else {
769	                // 物料号有效，检查是否需要记录
770	                int record_idx = find_record_by_sn(current_sn);
771	                if (record_idx < 0) {
772	                    // 新设备，记录SN和物料号
773	                    LOGI("New %s ear device, recording SN and model", cfg->ear_name);
774	                    int idx = add_or_update_record(current_sn, current_model);
775	                    if (idx >= 0) {
776	                        if (flash_store_save_record(&device_records[idx])) {
777	                            LOGI("Record saved to Flash");
778	                        } else {
779	                            LOGE("Failed to save record to Flash!");
780	                        }
781	                    }
782	                    LOG("sn: %02X%02X%02X%02X%02X%02X%02X%02X",
783	                        current_sn[0], current_sn[1], current_sn[2], current_sn[3],
784	                        current_sn[4], current_sn[5], current_sn[6], current_sn[7]);
785	                    LOG("model: %02X%02X%02X%02X%02X",
786	                        current_model[0], current_model[1], current_model[2],
787	                        current_model[3], current_model[4]);
788	                } else if (!device_records[record_idx].model_valid) {
789	                    // 已有记录但物料号无效，更新物料号
790	                    LOGI("Updating model number for existing SN");
791	                    int idx = add_or_update_record(current_sn, current_model);
792	                    if (idx >= 0) {
793	                        if (flash_store_save_record(&device_records[idx])) {
794	                            LOGI("Record saved to Flash");
795	                        } else {
796	                            LOGE("Failed to save record to Flash!");
797	                        }
798	                    }
799	                }
800	            }
801	            *skip_counter = 0;
802	        }
803	    }
804	
805	    xSemaphoreGive(xI2CMutex);
806	
807	    if (!read_success) {
808	        *skip_counter = 4;
809	        LOGW("Failed to read %s ear SN/Model, will retry later", cfg->ear_name);
810	        return 0;
811	    }
812	
813	    // 更新全局变量
814	    for (i = 0; i < SN_SIZE; i++) {
815	        cfg->last_sn[i] = current_sn[i];
816	        cfg->sn_buf[i]  = current_sn[i];
817	    }
818	    update_eeprom_status(cfg->ear_index, cfg->sn_buf, current_model);
819	
820	    return 1;
821	}
822	
823	#if FACTORY_VERSION
824	/**
825	 * @brief 工厂版本 - 处理单个耳朵设备(简化逻辑，不保存记录)
826	 */
827	static uint8_t process_ear_device_factory(const ear_config_t *cfg,
828	                                            uint8_t *current_sn,
829	                                            uint8_t *current_model,
830	                                            uint8_t *skip_counter)
831	{
832	    uint8_t read_success = 0;
833	    uint8_t need_write_back = 0;
834	    uint8_t new_model[MODEL_LEN] = {0};
835	    uint8_t i;
836	
837	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
838	        *skip_counter = 4;
839	        LOGW("Factory Mode: %s ear failed to take mutex", cfg->ear_name);
840	        return 0;
841	    }
842	
843	    // 1. 读取主物料号
844	    read_success = i2c_read_with_retry(cfg->hi2c, MODEL_ADDR, current_model, MODEL_LEN, 2);
845	
846	    if (read_success) {
847	        // 2. 检查物料号有效性
848	        if (current_model[1] == 0 && current_model[2] == 0 && current_model[3] == 0) {
849	            read_success = i2c_read_with_retry(cfg->hi2c, TYPE_ADDR, cfg->model_buf, TYPE_SIZE, 2);
850	        }
851	
852	        uint8_t model_valid = is_model_valid(current_model, NULL);
853	        if (!model_valid) {
854	            LOGW("Factory Mode: %s ear model is invalid! Attempting recovery...", cfg->ear_name);
855	            need_write_back = 1;
856	
857	            // 3. 读取备份物料号
858	            uint8_t current_backup_model[MODEL_BACK_LEN] = {0};
859	            read_success = i2c_read_with_retry(cfg->hi2c, MODEL_BACK_ADDR, current_backup_model, MODEL_BACK_LEN, 3);
860	
861	            if (read_success) {
862	                LOGI("Factory Mode: Backup model read OK.");
863	                LOG("Factory Mode: Backup model: %02X%02X%02X",
864	                    current_backup_model[0], current_backup_model[1], current_backup_model[2]);
865	
866	                // 4. 组合成标准格式
867	                new_model[0] = 0x11;
868	                new_model[1] = current_backup_model[0];
869	                new_model[2] = current_backup_model[1];
870	                new_model[3] = current_backup_model[2];
871	                new_model[4] = 0x02;
872	            } else {
873	                LOGE("Factory Mode: Failed to read backup model!");
874	                need_write_back = 0;
875	            }
876	        }
877	    } else {
878	        LOGW("Factory Mode: Failed to read %s ear main model!", cfg->ear_name);
879	    }
880	
881	    // 5. 如果需要恢复，执行写回
882	    if (need_write_back && read_success) {
883	        uint8_t write_success = i2c_write_with_retry(cfg->hi2c, MODEL_ADDR, new_model, MODEL_LEN, 3);
884	        if (write_success) {
885	            LOGI("Factory Mode: %s ear model recovered successfully.", cfg->ear_name);
886	            memcpy(current_model, new_model, MODEL_LEN);
887	        } else {
888	            LOGE("Factory Mode: Failed to write recovered model!");
889	        }
890	    }
891	
892	    // 6. 读取SN(仅用于显示)
893	    if (read_success) {
894	        i2c_read_with_retry(cfg->hi2c, SN_ADDR, current_sn, SN_LEN, 2);
895	    }
896	
897	    xSemaphoreGive(xI2CMutex);
898	
899	    if (!read_success) {
900	        *skip_counter = 4;
901	        LOGW("Factory Mode: Failed %s ear process, will retry.", cfg->ear_name);
902	        return 0;
903	    }
904	
905	    // 更新全局变量
906	    for (i = 0; i < SN_SIZE; i++) {
907	        cfg->last_sn[i] = current_sn[i];
908	        cfg->sn_buf[i]  = current_sn[i];
909	    }
910	    update_eeprom_status(cfg->ear_index, cfg->sn_buf, current_model);
911	    *skip_counter = 0;
912	
913	    return 1;
914	}
915	#endif /* FACTORY_VERSION */

