29	void I2C_Task(void *pvParameters)
30	{
31	    TickType_t xLastWakeTime    = xTaskGetTickCount();
32	    const TickType_t xFrequency = pdMS_TO_TICKS(100); /* 改为50ms */
33	    // static uint32_t run_count   = 0;
34	    // LOGI("I2C Task Started");
35	
36	    for (;;) {
37	        Command_t cmd             = {0};
38	        UBaseType_t message_count = uxQueueMessagesWaiting(xCommandQueue);
39	        if (message_count > 0)
40	            // LOGW("=======messages waiting in queue: %u", message_count);
41	            /* 从队列接收命令，非阻塞方式 */
42	            if (xQueueReceive(xCommandQueue, &cmd, 0) == pdPASS) {
43	                message_count = uxQueueMessagesWaiting(xCommandQueue);
44	                // LOGW("messages waiting in queue: %u", message_count);
45	                // LOG("I2C Task received command, Type:%d, Device:%d, datalen:%d, RegAddr:0x%04X ,ConnI2c1_flag:%d ,ConnI2c2_flag:%d", cmd.type, cmd.device, cmd.data_len, cmd.reg_addr, ConnI2c1_flag, ConnI2c2_flag);
46	                if (cmd.data_len > 2000) {
47	                    // LOGI("Command Data:");
48	                }
49	                /* 根据命令类型处理 */
50	                memset(response_data, 0, sizeof(response_data));
51	                /* 检查 cmd.data 是否有效 */
52	                if (cmd.data != NULL && cmd.resp_len > 0) {
53	                    uint16_t copy_len = (cmd.resp_len < sizeof(response_data)) ? cmd.resp_len : sizeof(response_data);
54	                    memcpy(response_data, cmd.data, copy_len);
55	                    // LOGI("Copied %u bytes from cmd.data to response_data", copy_len);
56	                } else {
57	                    // LOGE("Invalid cmd.data or cmd.resp_len: data=%p, resp_len=%u",
58	                    //   cmd.data, cmd.resp_len);
59	                }
60	                switch (cmd.type) {
61	                    case 1:
62	                        handle_watchdog(&cmd);
63	                        break;
64	                    case 2:
65	                        handle_reset(&cmd);
66	                        break;
67	                    case 3:
68	                        handle_read_register(&cmd);
69	                        break;
70	                    case 4:
71	                        handle_write_single(&cmd);
72	                        break;
73	                    case 5:
74	                        handle_write_multiple(&cmd);
75	                        break;
76	                    default:
77	                        break;
78	                }
79	
80	                /* 通知USB任务完成 */
81	                if (cmd.completion_sem != NULL) {
82	                    xSemaphoreGive(cmd.completion_sem);
83	                }
84	            }
85	
86	        /* 使用vTaskDelayUntil确保固定周期 */
87	        vTaskDelayUntil(&xLastWakeTime, xFrequency);
88	    }
89	}
