91	static void handle_send_response(Command_t *cmd)
92	{
93	    /* 发送响应到响应队列 */
94	    Response_t resp;
95	    resp.response       = response_data;
96	    resp.resp_len       = cmd->resp_len;
97	    resp.completion_sem = cmd->completion_sem;
98	    xQueueSend(xResponseQueue, &resp, portMAX_DELAY);
99	}
