102	static void handle_watchdog(Command_t *cmd)
103	{
104	    if (response_data[5] == 0x2E) {
105	        WATCHDOGFLAG     = 1;
106	        WATCHCOUNT       = timecunt;
107	        response_data[0] = 0x00;
108	        response_data[1] = 0x22;
109	        response_data[2] = 0x00;
110	        response_data[3] = 0x01;
111	        response_data[4] = 0x61;
112	        response_data[5] = 0xEE;
113	        cmd->resp_len    = 6;
114	
115	        handle_send_response(cmd);
116	    }
117	}
