119	/* 处理重置命令   0x04*/
120	static void handle_reset(Command_t *cmd)
121	{
122	
123	    if ((crc[0] == response_data[4]) && (crc[1] == response_data[5])) {
124	        if (cmd->device == 1) {
125	            /* 左耳重置 */
126	            uint16_t delay_time = ((response_data[2]) << 8) | response_data[3];
127	
128	            if (ConnI2c1_flag) {
129	                I2C1_Power_Off();
130	                LOG(   "Left ear power off, time count:%d", delay_time);
131	                I2c1ConfigGpioIn();
132	                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
133	                I2C1_Power_On();
134	
135	                response_data[0] = 0x01;
136	                response_data[1] = 0x04;
137	                response_data[2] = 0x00;
138	                response_data[3] = 0x22;
139	                response_data[4] = 0xc0;
140	                cmd->resp_len    = 5;
141	                handle_send_response(cmd);
142	
143	            } else {
144	                I2C1_Power_Off();
145	                I2c1ConfigGpioIn();
146	                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
147	                I2C1_Power_On();
148	
149	                response_data[0] = 0x01;
150	                response_data[1] = 0x04;
151	                response_data[2] = 0x01;
152	                response_data[3] = 0xe3;
153	                response_data[4] = 0x00;
154	                cmd->resp_len    = 5;
155	                handle_send_response(cmd);
156	            }
157	
158	        } else if (cmd->device == 2) {
159	            /* 右耳重置 */
160	            uint16_t delay_time = ((response_data[2]) << 8) | response_data[3];
161	
162	            if (ConnI2c2_flag) {
163	                // vTaskSuspendAll(); 
164	                // // delay_ms(50);
165	                // // vTaskDelay(pdMS_TO_TICKS(delay_time));
166	                // LOGI("Right ear power off, time count:%d", delay_time);
167	                // I2C2_Power_Off();
168	                // // vTaskDelay(1000000);
169	                // delay_ms(4000);
170	                // // uint64_t time_count = timecunt;
171	                // // while (time_count + 30 < timecunt);
172	                // LOGI("R1111111ight ear power off, time count:%d", delay_time);
173	                // I2C2_Power_On();
174	                //  xTaskResumeAll();
175	                I2c2ConfigGpioIn();
176	                I2C2_Power_Off();
177	                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
178	                I2C2_Power_On();
179	                response_data[0] = 0x02;
180	                response_data[1] = 0x04;
181	                response_data[2] = 0x00;
182	                response_data[3] = 0xd2;
183	                response_data[4] = 0xc0;
184	                cmd->resp_len    = 5;
185	                handle_send_response(cmd);
186	            } else {
187	                I2c2ConfigGpioIn();
188	                I2C2_Power_Off();
189	                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
190	                I2C2_Power_On();
191	
192	                response_data[0] = 0x02;
193	                response_data[1] = 0x04;
194	                response_data[2] = 0x01;
195	                response_data[3] = 0x13;
196	                response_data[4] = 0x00;
197	                cmd->resp_len    = 5;
198	                handle_send_response(cmd);
199	            }
200	        }
201	    }
202	}
