237	/* 处理写单个寄存器命令 (功能码 0x06) */
238	static void handle_write_single(Command_t *cmd)
239	{
240	    // LOGI("===xSemaphoreTake(xI2CMutex)2====");
241	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
242	        // LOGE("I2C mutex timeout for single write");
243	        return;
244	    }
245	    // LOGI("===xSemaphoreTake(xI2CMutex)2====");
246	    // LOG("");
247	    GetCrC(response_data, 7, crc);
248	    if ((crc[0] == response_data[cmd->data_len + 6]) && (crc[1] == response_data[cmd->data_len + 7])) {
249	        i2c_handle_type *hi2c = NULL;
250	
251	        /* 选择I2C设备 */
252	        if (cmd->device == 1) {
253	            if (ConnI2c1_flag) {
254	                hi2c = &hi2c1;
255	            }
256	        } else if (cmd->device == 2) {
257	            if (ConnI2c2_flag) {
258	                hi2c = &hi2c2;
259	            }
260	        }
261	
262	        if (hi2c == NULL) {
263	            // LOGE("Device %d not connected, cannot write", cmd->device);
264	            xSemaphoreGive(xI2CMutex);
265	            return;
266	        }
267	
268	        // LOGI("Writing single register, Device:%d, Addr:0x%04X, Data:0x%02X",
269	        //   cmd->device, cmd->reg_addr, cmd->data[0]);
270	
271	        /* 执行写操作 */
272	        if (i2c_write_with_retry(hi2c, cmd->reg_addr, &response_data[6], 1, 3)) {
273	            if (i2c_read_with_retry(hi2c, cmd->reg_addr, &response_data[6], 1, 3)) {
274	                GetCrC(response_data, 7, crc);
275	                response_data[7] = crc[0];
276	                response_data[8] = crc[1];
277	                cmd->resp_len    = 9;
278	                handle_send_response(cmd);
279	            } else {
280	                // LOGE("Failed to read back after write");
281	            }
282	        } else {
283	            // LOGE("Single register write failed");
284	        }
285	    }
286	    xSemaphoreGive(xI2CMutex);
287	}
