289	/* 处理EEPROM编程命令 */
290	static void handle_write_multiple(Command_t *cmd)
291	{
292	    // LOGI("===xSemaphoreTake(xI2CMutex)3====");
293	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
294	        // LOGE("I2C mutex timeout for programming");
295	        return;
296	    }
297	    // LOGI("===xSemaphoreTake(xI2CMutex)3====");
298	    // LOG("");
299	    i2c_handle_type *hi2c = NULL;
300	
301	    if ((crc[0] == response_data[cmd->data_len + 10]) && (crc[1] == response_data[cmd->data_len + 11])) {
302	        if (cmd->device == 1 && ConnI2c1_flag) {
303	            hi2c = &hi2c1;
304	        } else if (cmd->device == 2 && ConnI2c2_flag) {
305	            hi2c = &hi2c2;
306	        }
307	
308	        if (hi2c == NULL) {
309	            // LOGE("Device %d not connected, cannot program", cmd->device);
310	            xSemaphoreGive(xI2CMutex);
311	            return;
312	        }
313	
314	        // LOGI("Programming device %d, Address:0x%04X, Length:%u",
315	        //   cmd->device, cmd->reg_addr, cmd->data_len);
316	        
317	        // download_mode_flag = cmd->device; 
318	        // download_mode_delay= 50; 
319	        // Lcd_Pag_Index = LCD_Page_Dling;
320	        // if(!(LCD_Old_Page == Lcd_Pag_Index))
321	        // LCD_DISPLAY();
322	        // delay_ms(30);
323	        /* 计算页数 */
324	        uint16_t page_count   = (cmd->data_len + 63) / 64; // 正确的页数
325	        uint8_t write_success = 1;
326	
327	        /* 逐页写入 */
328	        for (uint16_t i = 0; i < page_count; i++) {
329	            uint16_t write_addr = cmd->reg_addr + 64 * i;
330	            uint16_t write_len  = (i == page_count - 1) ? (cmd->data_len % 64) : 64;
331	            if (write_len == 0) write_len = 64;
332	
333	            // LOGI("Writing page %u/%u, addr:0x%04X, len:%u",
334	            //      i + 1, page_count, write_addr, write_len);
335	
336	            /* 执行写操作 */
337	            if (!i2c_write_with_retry(hi2c, write_addr, &response_data[10 + 64 * i], write_len, 10)) {
338	                write_success = 0;
339	                break;
340	            }
341	
342	            // 根据写入长度动态调整延时
343	            if (write_len >= 32000) {
344	                delay_ms(10);
345	            } else if (write_len >= 1000) {
346	                delay_ms(7);
347	            } else {
348	                delay_ms(5);
349	            }
350	            // LOG("Page %u completed", i + 1);
351	        }
352	
353	        if (write_success) {
354	            // LOGI("Programming completed successfully");
355	
356	            /* 验证写入的数据 */
357	            uint8_t *verify_data = pvPortMalloc(cmd->data_len);
358	            if (verify_data != NULL) {
359	                if (i2c_read_with_retry(hi2c, cmd->reg_addr, verify_data, cmd->data_len, 3)) {
360	                    /* 逐字节验证 */
361	                    uint8_t verify_ok = 1;
362	                    for (uint16_t i = 0; i < cmd->data_len; i++) {
363	                        if (response_data[10 + i] != verify_data[i]) {
364	                            // LOGE("Verification failed at byte %u: Expected=0x%02X, Actual=0x%02X",
365	                            //   i, response_data[10 + i], verify_data[i]);
366	                            verify_ok = 0;
367	                            break;
368	                        } else {
369	                            // LOG("Verified byte %u: 0x%02X", i, verify_data[i]);
370	                        }
371	                    }
372	
373	                    if (verify_ok) {
374	                        // LOGI("Verification passed!");
375	                        MworeWr[2] = 0x00; /* 成功 */
376	                    } else {
377	                        // LOGE("Verification failed");
378	                        MworeWr[2] = 0x01; /* 验证失败 */
379	                    }
380	                } else {
381	                    // LOGE("Failed to read back for verification");
382	                    MworeWr[2] = 0x01; /* 读取失败 */
383	                }
384	                vPortFree(verify_data);
385	            } else {
386	                // LOGE("Memory allocation failed for verification");
387	                MworeWr[2] = 0x01; /* 写入失败 */
388	            }
389	        } else {
390	            // LOGE("Programming failed");
391	            MworeWr[2] = 0x01; /* 写入失败 */
392	        }
393	
394	        /* 构建响应 */
395	        MworeWr[0] = cmd->device;
396	        MworeWr[1] = 0x10; /* 功能码 */
397	        if (MworeWr[2] == 0x00) {
398	            if (cmd->device == 1) {
399	                MworeWr[3] = 0x2D;
400	                MworeWr[4] = 0xc0;
401	            } else if (cmd->device == 2) {
402	                MworeWr[3] = 0xDD;
403	                MworeWr[4] = 0xc0;
404	            }
405	        } else {
406	            if (cmd->device == 1) {
407	                MworeWr[3] = 0xec;
408	                MworeWr[4] = 0x00;
409	            } else if (cmd->device == 2) {
410	                MworeWr[3] = 0x1c;
411	                MworeWr[4] = 0x00; 
412	            }
413	        }
414	        memcpy(response_data, MworeWr, 5);
415	        cmd->resp_len = 5;
416	        handle_send_response(cmd);
417	        // download_mode_flag = 100;
418	    }
419	    xSemaphoreGive(xI2CMutex);
420	}
