424	void i2c_check_and_connect(i2c_handle_type *hi2c, void *i2c_port,
425	                           uint8_t *conn_flag, uint8_t *sn_buf, uint8_t *model_buf)
426	{
427	    uint8_t snnum[2]                      = {0x36, 0x36};
428	    uint8_t read_byte                     = 0;
429	    error_status status                   = ERROR;
430	    static uint8_t need_model_recovery[2] = {0, 0}; // 0:左耳, 1:右耳
431	    static uint8_t last_eeprom[64]        = {0};
432	    // 判断设备索引
433	    int dev_index = (i2c_port == I2C1_PORT) ? 0 : 1;
434	    // LOG("Checking I2C device on port %p (index %d)", i2c_port, dev_index);
435	    /* 设置I2C端口 */
436	    hi2c->i2cx = i2c_port;
437	    i2c_config(hi2c);
438	
439	    /* 读取连接地址 - 使用直接I2C读写，不重试 */
440	    status = i2c_memory_read(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS,
441	                             CONN_ADDR, &read_byte, 1, I2C_TIMEOUT);
442	
443	    if (status == 0) {
444	        if (0x36 == read_byte) {
445	            *conn_flag                        = 1;
446	            consecutive_fail_count[dev_index] = 1;
447	            // LOGI("[CONN-%p] Device connected, flag=0x%02X", i2c_port, read_byte);
448	        } else {
449	            last_eeprom[64 - 1] = 0x36; // 记录上次的EEPROM值，准备恢复
450	            LOGE("=================================[Dev_index-%d]  [CONN-%p]Writing connection flag", dev_index, i2c_port);
451	            fail_count[dev_index] ++;
452	            if(fail_count[dev_index] >=4){
453	
454	                status = i2c_memory_write(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS,
455	                                          0x7FC0, last_eeprom, 64, I2C_TIMEOUT);
456	                if(status == 0){
457	                    fail_count[dev_index] = 0;
458	                }
459	            }else{
460	                    status = 1;
461	            }
462	            if (status == 0) {
463	                /* 写入0x36 */
464	                
465	                // if (status == 0) {
466	                /* 短暂延时 */
467	                // vTaskDelay(pdMS_TO_TICKS(10));
468	
469	                /* 重新读取连接地址 */
470	                status = i2c_memory_read(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS,
471	                                         CONN_ADDR, &read_byte, 1, I2C_TIMEOUT);
472	
473	                if (status == 0 && 0x36 == read_byte) {
474	                    *conn_flag = 1;
475	                    consecutive_fail_count[dev_index] = 1;
476	                    LOGI("=================================[CONN-%p] Connection flag set, will check model number", i2c_port);
477	                } else {
478	                    LOGE("=============i2c_memory_write last_eeprom err====================");
479	                    *conn_flag = 0;
480	                }
481	                // }
482	            } else {
483	                LOGI("=============2====================");
484	                *conn_flag = 0;
485	            }
486	        }
487	    } else {
488	        consecutive_fail_count[dev_index] ++;
489	        if (consecutive_fail_count[dev_index ]>5)
490	        {
491	            consecutive_fail_count[dev_index] = 5;
492	        }
493	        // LOGI("=============3====================");
494	        // if (consecutive_fail_count[dev_index] >= 3) {
495	            *conn_flag = 0;
496	            // LOGI("=============3===============");
497	        // }
498	    }
499	}
