535	/* 构建响应数据 */
536	static void build_response(Command_t *cmd, uint8_t *data, uint16_t len)
537	{
538	    response_data[2] = response_data[6];
539	    response_data[3] = response_data[7];
540	    response_data[4] = response_data[8];
541	    response_data[5] = response_data[9];
542	
543	    for (uint16_t k = 0; k < len; k++) {
544	        response_data[6 + k] = data[k];
545	    }
546	
547	    GetCrC(response_data, 6 + len, crc);
548	    response_data[6 + len] = crc[0];
549	    response_data[7 + len] = crc[1];
550	    cmd->resp_len          = 8 + len;
551	    // LOGI("build_response- Type:%d, Device:%d, RegAddr:0x%04X, DataLen:%u, RespLen:%u",
552	    //   cmd->type, cmd->device, cmd->reg_addr, cmd->data_len, cmd->resp_len);
553	}

