26	void flash_store_init(void) {
27	    LOGI("[FlashStore] Init: Addr 0x%08X, Max Records=%d", 
28	         FLASH_STORE_START_ADDR, FLASH_MAX_RECORDS);
29	    
30	    // 尝试从Flash读取存储结构
31	    if (read_store_from_flash()) {
32	        LOGI("[FlashStore] Store loaded: write_index=%d, total_count=%d", 
