/**
  ******************************************************************************
  * @file    flash_store.c
  * @brief   基于 AT32F403A Flash 的数据记录存储模块实现（固定10条记录循环覆盖）
  ******************************************************************************
  */
#include "flash_store.h"
#include "log.h"
#include <string.h>

/* 全局变量 */
static flash_store_t s_store;                 /*!< 存储结构体（内存缓存） */
static uint8_t s_initialized = 0;             /*!< 是否已初始化 */

/* 私有函数声明 */
static uint8_t read_store_from_flash(void);
static uint8_t write_store_to_flash(void);
static uint8_t erase_page(uint32_t page_addr);
static uint16_t calculate_record_crc16(const device_record_t *record);
static uint8_t verify_record_crc(const flash_record_unit_t *unit);
static uint8_t validate_store_integrity(void);

/**
  * @brief  初始化Flash存储模块
  */
void flash_store_init(void) {
    LOGI("[FlashStore] Init: Addr 0x%08X, Max Records=%d", 
         FLASH_STORE_START_ADDR, FLASH_MAX_RECORDS);

    // 尝试从Flash读取存储结构
    if (read_store_from_flash()) {
        LOGI("[FlashStore] Store loaded: write_index=%d, total_count=%d", 
             s_store.header.write_index, s_store.header.total_count);
    } else {
        // 读取失败，初始化新的存储结构
        LOGI("[FlashStore] Initializing new store...");
        memset(&s_store, 0xFF, sizeof(flash_store_t));  // 全部填充为0xFF

        s_store.header.write_index = 0;
        s_store.header.total_count = 0;

        // 格式化并写入
        flash_store_format();
    }

    s_initialized = 1;
    LOGI("[FlashStore] Initialized successfully");
}

/**
  * @brief  从Flash加载所有有效记录到内存
  * @note   按照写入顺序的逆序加载，确保返回的是最新的记录
  */
uint16_t flash_store_load_all(device_record_t *records_buf, uint16_t buf_capacity) {
    if (!s_initialized) {
        LOGE("[FlashStore] Not initialized");
        return 0;
    }

    if (records_buf == NULL || buf_capacity == 0) {
        LOGE("[FlashStore] Invalid buffer parameters");
        return 0;
    }

    LOGI("[FlashStore] Loading %d records from Flash...", s_store.header.total_count);

    uint16_t loaded_count = 0;

    // 按照写入顺序的逆序加载记录（最新的在前）
    for (int8_t i = s_store.header.total_count - 1; i >= 0 && loaded_count < buf_capacity; i--) {
        uint8_t index = (s_store.header.write_index + FLASH_MAX_RECORDS - 1 - i) % FLASH_MAX_RECORDS;

        if (s_store.records[index].status == FLASH_UNIT_STATUS_VALID) {
            if (verify_record_crc(&s_store.records[index])) {
                memcpy(&records_buf[loaded_count], &s_store.records[index].record, 
                       sizeof(device_record_t));
                loaded_count++;
                // LOG("  [OK] Loaded record from index %d", index);
            } else {
                // LOGW(" [CRC Fail] at index %d, skipping.", index);
            }
        }
    }

    LOGI("[FlashStore] Load complete. %d valid record(s) loaded.", loaded_count);
    return loaded_count;
}

/**
  * @brief  保存一条记录到Flash（实现循环覆盖）
  * @note   保存第11条记录时覆盖第1条，第12条覆盖第2条，以此类推
  */
uint8_t flash_store_save_record(const device_record_t *record) {
    if (!s_initialized) {
        LOGE("[FlashStore] Not initialized");
        return 0;
    }

    if (record == NULL) {
        LOGE("[FlashStore] Save failed: NULL pointer.");
        return 0;
    }

    LOGI("[FlashStore] Saving record, current write_index=%d, total_count=%d", 
         s_store.header.write_index, s_store.header.total_count);

    // 1. 准备要写入的记录单元
    flash_record_unit_t unit_to_write;
    unit_to_write.status = FLASH_UNIT_STATUS_VALID;
    memcpy(&unit_to_write.record, record, sizeof(device_record_t));
    unit_to_write.crc16 = calculate_record_crc16(record);

    // 2. 在缓存中写入记录
    uint8_t write_index = s_store.header.write_index;
    memcpy(&s_store.records[write_index], &unit_to_write, sizeof(flash_record_unit_t));

    // 3. 更新头部信息
    s_store.header.write_index = (write_index + 1) % FLASH_MAX_RECORDS;

    if (s_store.header.total_count < FLASH_MAX_RECORDS) {
        s_store.header.total_count++;
    }

    LOGI("[FlashStore] Record saved to index %d, new write_index=%d, total_count=%d", 
         write_index, s_store.header.write_index, s_store.header.total_count);

    // 4. 将整个存储结构写入Flash
    if (write_store_to_flash()) {
        LOGI("[FlashStore] Flash write successful");
        return 1;
    } else {
        LOGE("[FlashStore] Flash write failed!");
        return 0;
    }
}

/**
  * @brief  格式化存储区
  */
void flash_store_format(void) {
    LOGI("[FlashStore] Formatting store...");

    // 初始化内存缓存
    memset(&s_store, 0xFF, sizeof(flash_store_t));
    s_store.header.write_index = 0;
    s_store.header.total_count = 0;

    // 写入Flash
    if (write_store_to_flash()) {
        LOGI("[FlashStore] Format successful");
    } else {
        LOGE("[FlashStore] Format failed!");
    }
}

/**
  * @brief  获取当前有效记录总数
  */
uint16_t flash_store_get_total_count(void) {
    return s_store.header.total_count;
}

/**
  * @brief  获取下一个要写入的索引
  */
uint8_t flash_store_get_next_index(void) {
    return s_store.header.write_index;
}

/* ========== 私有函数实现 ========== */

/**
  * @brief  从Flash读取整个存储结构
  */
static uint8_t read_store_from_flash(void) {
    // 1. 从Flash复制数据到内存缓存
    memcpy(&s_store, (void*)FLASH_STORE_START_ADDR, sizeof(flash_store_t));

    // 2. 验证存储完整性
    if (!validate_store_integrity()) {
        LOGW("[FlashStore] Store integrity check failed, assuming empty store");
        return 0;
    }

    return 1;
}

/**
  * @brief  将整个存储结构写入Flash
  */
static uint8_t write_store_to_flash(void) {
    // 1. 擦除目标页
    if (!erase_page(FLASH_STORE_START_ADDR)) {
        LOGE("[FlashStore] Page erase failed");
        return 0;
    }

    flash_unlock();

    // 2. 计算需要写入的半字数
    uint16_t halfword_count = sizeof(flash_store_t) / 2;
    uint16_t *p_data = (uint16_t*)&s_store;

    // 3. 逐半字写入
    for (uint16_t i = 0; i < halfword_count; i++) {
        uint32_t write_addr = FLASH_STORE_START_ADDR + (i * 2);
        flash_status_type status = flash_halfword_program(write_addr, p_data[i]);

        if (status != FLASH_OPERATE_DONE) {
            LOGE("[FlashStore] Write failed at 0x%08X, status=%d", write_addr, status);
            flash_lock();
            return 0;
        }
    }

    flash_lock();

    return 1;
}

/**
  * @brief  擦除指定页
  */
static uint8_t erase_page(uint32_t page_addr) {
    flash_unlock();

    flash_status_type status = flash_sector_erase(page_addr);

    flash_lock();

    if (status == FLASH_OPERATE_DONE) {
        return 1;
    } else {
        LOGE("[FlashStore] Page erase failed at 0x%08X, status=%d", page_addr, status);
        return 0;
    }
}

/**
  * @brief  计算一条记录的CRC16值
  */
static uint16_t calculate_record_crc16(const device_record_t *record) {
    uint8_t crc_bytes[2] = {0};
    if (record) {
        GetCrC((uint8_t*)record, sizeof(device_record_t), crc_bytes);
    }
    return (crc_bytes[1] << 8) | crc_bytes[0];
}

/**
  * @brief  验证存储单元的CRC
  */
static uint8_t verify_record_crc(const flash_record_unit_t *unit) {
    if (unit->status != FLASH_UNIT_STATUS_VALID) {
        return 0;
    }
    uint16_t calculated_crc = calculate_record_crc16(&unit->record);
    return (unit->crc16 == calculated_crc);
}

/**
  * @brief  验证存储完整性
  */
static uint8_t validate_store_integrity(void) {
    // 检查写入索引是否有效
    if (s_store.header.write_index >= FLASH_MAX_RECORDS) {
        return 0;
    }

    // 检查总记录数是否有效
    if (s_store.header.total_count > FLASH_MAX_RECORDS) {
        return 0;
    }

    return 1;
}

