void Watchdog_Init(void)
{
    /* 1. 检查并清除之前的看门狗复位标志 */
    if (crm_flag_get(CRM_WDT_RESET_FLAG) != RESET) {
        crm_flag_clear(CRM_WDT_RESET_FLAG);
        LOGI("System recovered from a Watchdog reset.");
    }

    /* 2. 解锁并配置看门狗寄存器 */
    wdt_register_write_enable(TRUE);
    
    /* 关键修改：设置更短的超时时间
     * 假设LSI = 40kHz
     * 分频选择 WDT_CLK_DIV_64, 时钟频率 = 40k / 64 = 1250 Hz
     * 重载值设为 625，则超时时间 = 625 / 625 Hz = 2.0 秒
     */
    wdt_divider_set(WDT_CLK_DIV_64);      // 修改了分频系数
    // wdt_reload_value_set(1250*10000);            // 修改了重载值，目标约1秒超时
    wdt_reload_value_set(1250);            // 修改了重载值，目标约1秒超时
    
    /* 3. 关初始化后立即执行首次喂狗！
     */
    wdt_counter_reload();
    
    /* 4. 最后，使能看门狗 */
    wdt_enable();
    
    LOGI("Independent Watchdog Enabled. Timeout configured to ~1 second.");
}

/**
