/**
 * @file     usb_task.c
 * @brief    USB通信任务 - 基于原有StateSwitch逻辑
 */
#include "usb_task.h"
#include "init.h"
#include "i2c_task.h"

#include "log.h"

/* 外部变量声明 */

extern uint16_t framecout;
extern uint8_t FrameFlag;
extern uint8_t FrameFinish;
extern uint8_t ConnI2c1_flag, ConnI2c2_flag;
extern usbd_core_type usb_core_dev;

/* 模块内部变量 */
static uint8_t UsbRxBuf[64] = {0x00};
static uint16_t data_len    = 0;
static uint8_t usb_rx_frame[E32K_SIZE];
static uint16_t usb_rx_index = 0;

void USB_Task(void *pvParameters)
{
    Command_t cmd         = {0};
    uint8_t function_code = 0;

    LOGI("USB Task Started");

    /* 使用vTaskDelayUntil实现固定周期 */
    TickType_t xLastWakeTime    = xTaskGetTickCount();
    const TickType_t xFrequency = pdMS_TO_TICKS(100); /* 5ms运行一次 */
    // static uint32_t run_count = 0;
    for (;;) {
        // run_count++;
        // if(run_count > 100) {
        // LOG("USB Task Running... Time: %llu", timecunt);
        //     run_count = 0;
        // }
        /* 接收USB数据 */
        data_len = usb_vcp_get_rxdata(&usb_core_dev, UsbRxBuf);

        if (data_len > 0) {
            /* 存储到帧缓冲区 */
            if ((usb_rx_index + data_len) <= E32K_SIZE) {
                for (uint8_t i = 0; i < data_len; i++) {
                    usb_rx_frame[usb_rx_index + i] = UsbRxBuf[i];
                }
                usb_rx_index += data_len;
                FrameFlag = 0;
                // LOG("Received %u bytes from USB", data_len);
                memset(UsbRxBuf, 0, sizeof(UsbRxBuf));
            } else {
                LOGE("USB buffer overflow");
                usb_rx_index = 0;
            }
        } else {
            /* 检查是否接收到完整帧 */
            if (FrameFlag == 0 && usb_rx_index >= 2) {
                uint8_t device = usb_rx_frame[0];
                function_code  = usb_rx_frame[1];

                LOGI("USB_TASK, Device:%d, Function:0x%02X, Len:%u", device, function_code, usb_rx_index);
                /* 调试打印 */
                for (uint16_t i = 0; i < usb_rx_index && i < 10; i++) {
                    LOG(" %02X", usb_rx_frame[i]);
                }
                // LOG("Write length: %u bytes", ((uint16_t)usb_rx_frame[8] << 8) | usb_rx_frame[9]);
                /* 解析命令 */
                cmd.type     = 0;
                cmd.device   = device;
                cmd.reg_addr = 0;
                cmd.data_len = 0;
                cmd.data     = usb_rx_frame;
                cmd.resp_len = usb_rx_index;

                /* 根据功能码设置命令类型 */
                switch (function_code) {
                    case 0x22:
                        cmd.type = 1;
                        for (uint16_t i = 0; i < usb_rx_index; i++) {
                            cmd.response[i] = usb_rx_frame[i];
                        }
                        break; /* 看门狗 */
                    case 0x04:
                        cmd.type = 2;
                        GetCrC(usb_rx_frame, 4, crc);
                        for (uint16_t i = 0; i < usb_rx_index; i++) {
                            cmd.response[i] = usb_rx_frame[i];
                        }
                        break; /* 重置 */
                    case 0x03: /* 读寄存器 */
                        cmd.type     = 3;
                        cmd.reg_addr = (usb_rx_frame[4] << 8) | usb_rx_frame[5];
                        cmd.data_len = (usb_rx_frame[8] << 8) | usb_rx_frame[9];
                        GetCrC(usb_rx_frame, 10, crc);
                        if (cmd.device == 0) {
                            cmd.type = 0; /* 特例：用于访问左右耳连接状态。 */
                            if ((crc[0] == usb_rx_frame[10]) && (crc[1] == usb_rx_frame[11])) {
                                if (0 == usb_rx_frame[0]) {
                                    uint8_t stutas1 = 0;
                                    stutas1 |= ConnI2c1_flag;
                                    stutas1 |= (ConnI2c2_flag << 1);
                                    switch (stutas1) {
                                        case 0:
                                            connectstatus[6] = 0x00;
                                            connectstatus[7] = 0x1A;
                                            connectstatus[8] = 0xA3;
                                            break;
                                        case 1:
                                            connectstatus[6] = 0x01;
                                            connectstatus[7] = 0xDB;
                                            connectstatus[8] = 0x63;
                                            break;
                                        case 2:
                                            connectstatus[6] = 0x02;
                                            connectstatus[7] = 0x9B;
                                            connectstatus[8] = 0x62;
                                            break;
                                        case 3:
                                            connectstatus[6] = 0x03;
                                            connectstatus[7] = 0x5A;
                                            connectstatus[8] = 0xA2;
                                            break;
                                        default:
                                            break;
                                    }
                                    usb_send_response_data(connectstatus, 9);
                                }
                            }
                        } else {
                            if (!((crc[0] == usb_rx_frame[10]) && (crc[1] == usb_rx_frame[11]))) {
                                LOGE("CRC check failed for device %d", cmd.device);
                                cmd.type = 0; // CRC校验失败，不发送命令
                            } else {
                                for (uint16_t i = 0; i < usb_rx_index; i++) {
                                    cmd.response[i] = usb_rx_frame[i];
                                }
                            }
                        }
                        break;
                    case 0x06: /* 写单个寄存器 */
                        cmd.type     = 4;
                        cmd.reg_addr = ((uint16_t)(usb_rx_frame[4]) << 8) | usb_rx_frame[5];
                        cmd.data_len = 1;
                        for (uint16_t i = 0; i < usb_rx_index; i++) {
                            cmd.response[i] = usb_rx_frame[i];
                        }
                        break;
                    case 0x10: /* 写多个寄存器 */
                        cmd.type     = 5;
                        cmd.reg_addr = ((uint16_t)(usb_rx_frame[4]) << 8) | usb_rx_frame[5];
                        cmd.data_len = ((uint16_t)(usb_rx_frame[8]) << 8) | usb_rx_frame[9];
                        if (usb_rx_index < (cmd.data_len + 5)) {
                            LOGW("0x10 command incomplete: %u/%u bytes, waiting...",
                                 usb_rx_index, cmd.data_len);
                            continue; // 继续等待
                        }
                        GetCrC(usb_rx_frame, cmd.data_len + 10, crc);

                        uint32_t end_addr = cmd.reg_addr + cmd.data_len - 1;

                        if ((cmd.reg_addr <= SN_ADDR + SN_SIZE - 1) && (end_addr >= SN_ADDR)) {
                            LOGW("Warning: Write operation may overwrite SN area!");
                            LOGW("SN area: 0x%04X-0x%04X", SN_ADDR, SN_ADDR + SN_SIZE - 1);
                            LOGW("This write: 0x%04X-0x%04X", cmd.reg_addr, end_addr);
                            // cmd.type = 0; /* 特例：禁止写入SN区域 */
                        }
                        break;
                    default:
                        LOGW("Unknown function code: 0x%02X", function_code);
                        break;
                }

                /* 发送命令到I2C任务 */
                if (cmd.type != 0) {
                    cmd.completion_sem = xSemaphoreCreateBinary();
                    if (cmd.completion_sem != NULL) {
                        if (xQueueSend(xCommandQueue, &cmd, portMAX_DELAY) == pdPASS) {
                            /* 等待I2C任务完成 */
                            if (xSemaphoreTake(cmd.completion_sem, pdMS_TO_TICKS(25000) ) == pdTRUE) {

                                Response_t resp;
                                if (xQueueReceive(xResponseQueue, &resp, pdMS_TO_TICKS(5000)) == pdPASS) {
                                    if (resp.resp_len > 0) {
                                        // memcpy(cmd.response, resp.response, resp.resp_len);
                                        // cmd.resp_len = resp.resp_len;
                                        LOGI("Command processed - Type:%d, Device:%d, RegAddr:0x%04X, DataLen:%u, RespLen:%u",
                                             cmd.type, cmd.device, cmd.reg_addr, cmd.data_len, cmd.resp_len);
                                        /* 发送响应 */
                                        usb_send_response(resp.resp_len);
                                    } else {
                                        LOGI("Failed to get response in time");
                                    }
                                }
                            } else {
                                LOGE("Command 0x%02X timeout", function_code);
                            }
                        }
                        vSemaphoreDelete(cmd.completion_sem);
                    }
                }
                memset(usb_rx_frame, 0, sizeof(usb_rx_frame)); // 清空帧缓冲区
                memset(UsbRxBuf, 0, sizeof(UsbRxBuf));         // 清空USB接收缓冲区
                memset(&cmd, 0, sizeof(Command_t));
                /* 清空缓冲区 */
                usb_rx_index = 0;
                FrameFlag    = 1;
                FrameFinish  = 1;
            }
        }

        vTaskDelayUntil(&xLastWakeTime, xFrequency);
    }
}

/* USB发送响应 */
void usb_send_response(uint16_t len)
{
    if (rxdata == NULL || len == 0) {
        LOGW("usb_send_response: Invalid data or length");
        return;
    }

    /* 打印要发送的响应数据 */
    LOGI("USB Response: Length: %u bytes, Data:", len);
    LOG("");
    for (uint16_t i = 0; i < len && i < 20; i++) {
        LOG("%02X ", response_data[i]);
    }
    if (xSemaphoreTake(xUSBMutex, portMAX_DELAY) == pdTRUE) {
        LOGI("Sending USB response, Length: %u bytes", len);
        usb_vcp_send_data(&usb_core_dev, response_data, len);
        xSemaphoreGive(xUSBMutex);
    }
}
/* USB发送响应 */
void usb_send_response_data(uint8_t *data, uint16_t len)
{
    if (data == NULL || len == 0) {
        LOGW("usb_send_response: Invalid data or length");
        return;
    }

    /* 打印要发送的响应数据 */
    LOGI("usb_send_response_data: Length: %u bytes, Data:", len);
    for (uint16_t i = 0; i < len && i < 20; i++) {
        LOG("%02X ", data[i]);
    }
    if (xSemaphoreTake(xUSBMutex, portMAX_DELAY) == pdTRUE) {
        LOGI("Sending usb_send_response_data, Length: %u bytes", len);
        usb_vcp_send_data(&usb_core_dev, data, len);
        xSemaphoreGive(xUSBMutex);
    }
}

